Parsing XML from untrusted sources is extremely dangerous by default. Most XML parsers enable external entity processing, which allows attackers to read files from your server, perform SSRF attacks, or even achieve remote code execution.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const libxmljs = require('libxmljs');
const fs = require('fs');

const app = express();
app.use(express.text({ type: 'application/xml' }));

app.post('/api/parse-xml', (req, res) => {
  try {
    // VULNERABLE: Default parser settings allow XXE
    const xmlDoc = libxmljs.parseXml(req.body);

    // Extract data from XML
    const root = xmlDoc.root();
    const username = root.get('//username').text();
    const email = root.get('//email').text();

    res.json({
      success: true,
      data: { username, email }
    });
  } catch (error) {
    res.status(400).json({ error: 'Invalid XML' });
  }
});

app.listen(3000);
```

**Attack Payload**:
```xml
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE foo [
  <!ENTITY xxe SYSTEM "file:///etc/passwd">
]>
<user>
  <username>&xxe;</username>
  <email>attacker@evil.com</email>
</user>
```

**AWS Credential Theft Payload**:
```xml
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE foo [
  <!ENTITY xxe SYSTEM "file:///home/app/.aws/credentials">
]>
<user>
  <username>&xxe;</username>
  <email>test@test.com</email>
</user>
```

**SSRF Attack Payload**:
```xml
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE foo [
  <!ENTITY xxe SYSTEM "http://169.254.169.254/latest/meta-data/iam/security-credentials/">
]>
<user>
  <username>&xxe;</username>
  <email>test@test.com</email>
</user>
```

**Why This Is Dangerous**:
- External entities allow reading arbitrary files from the server filesystem
- SSRF attacks can access internal services, cloud metadata endpoints, and private networks
- Billion laughs attack can cause denial of service through exponential entity expansion
- Some parsers allow PHP/expect wrappers enabling remote code execution

**SECURE VERSION**:

```javascript
const express = require('express');
const libxmljs = require('libxmljs');

const app = express();

// Limit XML payload size to prevent DoS
app.use(express.text({ 
  type: 'application/xml',
  limit: '100kb'
}));

app.post('/api/parse-xml', (req, res) => {
  try {
    // SECURE: Disable external entities and DTD processing
    const parserOptions = {
      noent: false,      // Do NOT expand entities
      dtdload: false,    // Do NOT load external DTD
      dtdvalid: false,   // Do NOT validate against DTD
      nonet: true,       // Disable network access
      nocdata: false,    // Keep CDATA as-is
      noblanks: true     // Remove blank nodes
    };

    const xmlDoc = libxmljs.parseXml(req.body, parserOptions);

    // Validate expected structure
    const root = xmlDoc.root();
    if (!root || root.name() !== 'user') {
      return res.status(400).json({ error: 'Invalid XML structure' });
    }

    const usernameNode = root.get('//username');
    const emailNode = root.get('//email');

    if (!usernameNode || !emailNode) {
      return res.status(400).json({ error: 'Missing required fields' });
    }

    const username = usernameNode.text();
    const email = emailNode.text();

    // Additional validation
    if (username.length > 100 || email.length > 255) {
      return res.status(400).json({ error: 'Field length exceeded' });
    }

    res.json({
      success: true,
      data: { username, email }
    });
  } catch (error) {
    console.error('XML parsing error:', error.message);
    res.status(400).json({ error: 'Invalid XML format' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- `noent: false` - Prevents entity expansion, blocking XXE attacks
- `dtdload: false` - Prevents loading external DTD files
- `nonet: true` - Disables all network access during parsing, blocking SSRF
- Payload size limit prevents denial of service attacks
- Structure validation ensures only expected XML format is processed

Different XML parsers have different default behaviors and configuration options. Here's how to secure the most popular Node.js XML libraries in production.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const { XMLParser, XMLValidator } = require('fast-xml-parser');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();
app.use(helmet());

// Rate limiting for XML endpoints
const xmlLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // 100 requests per window
  message: { error: 'Too many requests, please try again later' }
});

// Strict payload limits
app.use(express.text({ 
  type: ['application/xml', 'text/xml'],
  limit: '50kb'
}));

// Secure XML parser configuration factory
function createSecureXMLParser() {
  return new XMLParser({
    // SECURITY: Disable all dangerous features
    allowBooleanAttributes: false,
    ignoreAttributes: false,
    ignoreDeclaration: true,
    ignorePiTags: true,

    // Prevent entity expansion attacks
    processEntities: false,
    htmlEntities: false,

    // Limit parsing depth to prevent stack overflow
    parseTagValue: true,
    trimValues: true,

    // Disable comment processing
    commentPropName: false,

    // Custom tag validation
    isArray: (name, jpath, isLeafNode, isAttribute) => {
      // Define which tags should always be arrays
      const arrayTags = ['item', 'entry', 'record'];
      return arrayTags.includes(name);
    }
  });
}

// Pre-parsing security validation
function validateXMLSecurity(xmlString) {
  const dangerousPatterns = [
    /<!ENTITY/i,           // External entities
    /<!DOCTYPE/i,          // DTD declarations
    /SYSTEM\s+["']/i,      // SYSTEM keyword
    /PUBLIC\s+["']/i,      // PUBLIC keyword
    /<!\[CDATA\[.*\]\]>/is // CDATA sections (optional)
  ];

  for (const pattern of dangerousPatterns) {
    if (pattern.test(xmlString)) {
      return {
        valid: false,
        reason: 'XML contains potentially dangerous content'
      };
    }
  }

  // Check for entity expansion (billion laughs)
  const entityCount = (xmlString.match(/&\w+;/g) || []).length;
  if (entityCount > 100) {
    return {
      valid: false,
      reason: 'Too many entity references'
    };
  }

  return { valid: true };
}

// Audit logging
function logXMLParseAttempt(req, success, details = {}) {
  const logEntry = {
    timestamp: new Date().toISOString(),
    ip: req.ip,
    userAgent: req.get('user-agent'),
    endpoint: req.path,
    success,
    payloadSize: req.body?.length || 0,
    ...details
  };

  // Production: Send to SIEM/logging service
  console.log(JSON.stringify(logEntry));
}

app.post('/api/upload/xml', xmlLimiter, async (req, res) => {
  const startTime = Date.now();

  try {
    // Layer 1: Content-Type validation
    const contentType = req.get('content-type');
    if (!contentType?.includes('xml')) {
      logXMLParseAttempt(req, false, { reason: 'Invalid content type' });
      return res.status(415).json({ error: 'Content-Type must be XML' });
    }

    // Layer 2: Pre-parsing security scan
    const securityCheck = validateXMLSecurity(req.body);
    if (!securityCheck.valid) {
      logXMLParseAttempt(req, false, { 
        reason: securityCheck.reason,
        blocked: true 
      });
      return res.status(400).json({ error: 'Invalid XML content' });
    }

    // Layer 3: XML well-formedness validation
    const validationResult = XMLValidator.validate(req.body, {
      allowBooleanAttributes: false
    });

    if (validationResult !== true) {
      logXMLParseAttempt(req, false, { 
        reason: 'Malformed XML',
        error: validationResult.err?.msg 
      });
      return res.status(400).json({ error: 'Malformed XML document' });
    }

    // Layer 4: Secure parsing
    const parser = createSecureXMLParser();
    const result = parser.parse(req.body);

    // Layer 5: Schema/structure validation
    if (!result.user || typeof result.user !== 'object') {
      logXMLParseAttempt(req, false, { reason: 'Invalid structure' });
      return res.status(400).json({ error: 'Invalid XML structure' });
    }

    // Layer 6: Data validation
    const { username, email } = result.user;

    if (!username || typeof username !== 'string') {
      return res.status(400).json({ error: 'Missing or invalid username' });
    }

    if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      return res.status(400).json({ error: 'Missing or invalid email' });
    }

    // Sanitize output
    const sanitizedData = {
      username: username.slice(0, 100).replace(/[<>&"']/g, ''),
      email: email.slice(0, 255).toLowerCase()
    };

    logXMLParseAttempt(req, true, { 
      processingTime: Date.now() - startTime 
    });

    res.json({
      success: true,
      data: sanitizedData
    });

  } catch (error) {
    logXMLParseAttempt(req, false, { 
      reason: 'Parse exception',
      error: error.message 
    });

    // Generic error - don't leak parser details
    res.status(500).json({ error: 'Unable to process request' });
  }
});

// Alternative: xml2js secure configuration
const xml2js = require('xml2js');

function createSecureXml2jsParser() {
  return new xml2js.Parser({
    // SECURITY: Strict mode disables dangerous features
    strict: true,

    // Prevent attribute injection
    attrNameProcessors: [(name) => name.replace(/[^a-zA-Z0-9_]/g, '')],

    // Limit nesting depth
    xmlns: false,

    // Normalize whitespace
    normalize: true,
    normalizeTags: true,

    // Explicit array handling
    explicitArray: false,
    explicitRoot: true,

    // Character handling
    trim: true
  });
}

app.post('/api/upload/xml-v2', xmlLimiter, async (req, res) => {
  try {
    const securityCheck = validateXMLSecurity(req.body);
    if (!securityCheck.valid) {
      return res.status(400).json({ error: 'Invalid XML content' });
    }

    const parser = createSecureXml2jsParser();
    const result = await parser.parseStringPromise(req.body);

    // Process result safely
    res.json({ success: true, data: result });

  } catch (error) {
    res.status(400).json({ error: 'Unable to process XML' });
  }
});

// Health check endpoint
app.get('/health', (req, res) => {
  res.json({ status: 'healthy', timestamp: new Date().toISOString() });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Secure XML service running on port ${PORT}`);
});
```

**Defense in Depth Layers**:

1. **Pre-parsing regex scan** - Blocks XXE payloads before they reach the parser:
```javascript
const dangerousPatterns = [
  /<!ENTITY/i,
  /<!DOCTYPE/i,
  /SYSTEM\s+["']/i
];
// Reject if any pattern matches
```

2. **Parser configuration hardening** - Disable dangerous features at the parser level:
```javascript
const parser = new XMLParser({
  processEntities: false,  // Critical: prevents entity expansion
  ignoreDeclaration: true, // Ignores XML declaration
  ignorePiTags: true       // Ignores processing instructions
});
```

3. **Schema validation** - Ensure XML matches expected structure:
```javascript
if (!result.user || !result.user.username) {
  throw new Error('Invalid structure');
}
```

**Additional Protections**:
- **Payload size limits** - 50KB max prevents memory exhaustion attacks
- **Rate limiting** - 100 requests per 15 minutes prevents automated attacks
- **Audit logging** - All parse attempts logged with IP, user-agent, success/failure for SOC monitoring
- **Content-Type enforcement** - Only accepts application/xml or text/xml
- **Output sanitization** - Strips potentially dangerous characters from parsed values
- **Generic error messages** - Never expose parser internals or file paths in error responses
- **Timeout handling** - Set parsing timeouts to prevent slow-parsing DoS attacks

Using DocumentBuilder with default settings is extremely dangerous! The default configuration allows XML External Entity (XXE) attacks, which were exploited in the 2024 Ivanti Connect Secure breach (CVE-2024-21893) affecting 1,700+ organizations.

**VULNERABLE CODE**:

```java
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import org.w3c.dom.Document;
import org.w3c.dom.NodeList;
import java.io.InputStream;

public class XMLProcessor {

    public Document parseUserXML(InputStream xmlInput) throws Exception {
        // VULNERABLE: Default DocumentBuilder allows XXE attacks
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        DocumentBuilder builder = factory.newDocumentBuilder();

        // This will process external entities in the XML!
        Document doc = builder.parse(xmlInput);
        return doc;
    }

    public String extractUserData(InputStream xmlInput) throws Exception {
        Document doc = parseUserXML(xmlInput);
        NodeList nodes = doc.getElementsByTagName("username");
        if (nodes.getLength() > 0) {
            return nodes.item(0).getTextContent();
        }
        return null;
    }
}
```

**Attack Payload**:
```xml
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE foo [
  <!ENTITY xxe SYSTEM "file:///etc/passwd">
]>
<user>
  <username>&xxe;</username>
</user>
```

**Advanced SSRF Attack**:
```xml
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE foo [
  <!ENTITY xxe SYSTEM "http://internal-server:8080/admin/secrets">
]>
<user>
  <username>&xxe;</username>
</user>
```

**Why This Is Dangerous**:
- External entities allow reading ANY file the application can access (/etc/passwd, application.properties, AWS credentials)
- SSRF attacks can reach internal services not exposed to the internet
- Billion Laughs attack can cause denial of service through entity expansion
- Parameter entities can exfiltrate data to attacker-controlled servers

**SECURE VERSION**:

```java
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.XMLConstants;
import org.w3c.dom.Document;
import org.w3c.dom.NodeList;
import java.io.InputStream;
import java.util.logging.Logger;

public class SecureXMLProcessor {

    private static final Logger logger = Logger.getLogger(SecureXMLProcessor.class.getName());

    public Document parseUserXML(InputStream xmlInput) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();

        // SECURE: Disable all external entities and DTDs
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

        // Additional hardening
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);
        factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
        factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

        DocumentBuilder builder = factory.newDocumentBuilder();

        logger.info("Parsing XML document with secure settings");
        Document doc = builder.parse(xmlInput);
        return doc;
    }

    public String extractUserData(InputStream xmlInput) throws Exception {
        Document doc = parseUserXML(xmlInput);
        NodeList nodes = doc.getElementsByTagName("username");
        if (nodes.getLength() > 0) {
            return nodes.item(0).getTextContent();
        }
        return null;
    }
}
```

**Key Security Controls**:
- `disallow-doctype-decl`: Completely blocks DOCTYPE declarations, preventing all XXE attacks
- `external-general-entities` and `external-parameter-entities`: Disables entity resolution even if DOCTYPE is somehow processed
- `ACCESS_EXTERNAL_DTD` and `ACCESS_EXTERNAL_SCHEMA`: Prevents loading external DTD/Schema files

Excellent question! Different XML parsers require different security configurations. Here's a comprehensive production-ready approach that covers multiple XML libraries and integrates with Spring Boot REST APIs.

**PRODUCTION PATTERN**:

```java
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.SAXParser;
import javax.xml.parsers.SAXParserFactory;
import javax.xml.stream.XMLInputFactory;
import javax.xml.stream.XMLStreamReader;
import javax.xml.XMLConstants;
import javax.xml.transform.TransformerFactory;
import org.springframework.web.bind.annotation.*;
import org.springframework.http.ResponseEntity;
import org.springframework.http.HttpStatus;
import org.w3c.dom.Document;
import org.xml.sax.InputSource;
import java.io.InputStream;
import java.io.StringReader;
import java.util.logging.Logger;

@RestController
@RequestMapping("/api/xml")
public class SecureXMLController {

    private static final Logger logger = Logger.getLogger(SecureXMLController.class.getName());
    private static final int MAX_XML_SIZE = 1024 * 1024; // 1MB limit

    // Secure DocumentBuilderFactory singleton
    private static final DocumentBuilderFactory SECURE_DOC_FACTORY;
    private static final SAXParserFactory SECURE_SAX_FACTORY;
    private static final XMLInputFactory SECURE_STAX_FACTORY;
    private static final TransformerFactory SECURE_TRANSFORMER_FACTORY;

    static {
        // Initialize secure DocumentBuilderFactory
        SECURE_DOC_FACTORY = DocumentBuilderFactory.newInstance();
        try {
            SECURE_DOC_FACTORY.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            SECURE_DOC_FACTORY.setFeature("http://xml.org/sax/features/external-general-entities", false);
            SECURE_DOC_FACTORY.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            SECURE_DOC_FACTORY.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            SECURE_DOC_FACTORY.setXIncludeAware(false);
            SECURE_DOC_FACTORY.setExpandEntityReferences(false);
            SECURE_DOC_FACTORY.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            SECURE_DOC_FACTORY.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");
        } catch (Exception e) {
            throw new RuntimeException("Failed to configure secure XML parser", e);
        }

        // Initialize secure SAXParserFactory
        SECURE_SAX_FACTORY = SAXParserFactory.newInstance();
        try {
            SECURE_SAX_FACTORY.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            SECURE_SAX_FACTORY.setFeature("http://xml.org/sax/features/external-general-entities", false);
            SECURE_SAX_FACTORY.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            SECURE_SAX_FACTORY.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        } catch (Exception e) {
            throw new RuntimeException("Failed to configure secure SAX parser", e);
        }

        // Initialize secure StAX factory
        SECURE_STAX_FACTORY = XMLInputFactory.newInstance();
        SECURE_STAX_FACTORY.setProperty(XMLInputFactory.SUPPORT_DTD, false);
        SECURE_STAX_FACTORY.setProperty(XMLInputFactory.IS_SUPPORTING_EXTERNAL_ENTITIES, false);
        SECURE_STAX_FACTORY.setProperty(XMLConstants.ACCESS_EXTERNAL_DTD, "");
        SECURE_STAX_FACTORY.setProperty(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

        // Initialize secure TransformerFactory
        SECURE_TRANSFORMER_FACTORY = TransformerFactory.newInstance();
        try {
            SECURE_TRANSFORMER_FACTORY.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
            SECURE_TRANSFORMER_FACTORY.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            SECURE_TRANSFORMER_FACTORY.setAttribute(XMLConstants.ACCESS_EXTERNAL_STYLESHEET, "");
        } catch (Exception e) {
            throw new RuntimeException("Failed to configure secure transformer", e);
        }
    }

    @PostMapping("/parse")
    public ResponseEntity<String> parseXML(
            @RequestBody byte[] xmlData,
            @RequestHeader(value = "X-Request-ID", required = false) String requestId) {

        String traceId = requestId != null ? requestId : java.util.UUID.randomUUID().toString();

        // Defense Layer 1: Size validation
        if (xmlData == null || xmlData.length == 0) {
            logger.warning(String.format("[%s] Empty XML payload rejected", traceId));
            return ResponseEntity.badRequest().body("XML payload required");
        }

        if (xmlData.length > MAX_XML_SIZE) {
            logger.warning(String.format("[%s] XML payload too large: %d bytes", traceId, xmlData.length));
            return ResponseEntity.status(HttpStatus.PAYLOAD_TOO_LARGE)
                    .body("XML payload exceeds maximum size");
        }

        // Defense Layer 2: Content pre-validation
        String xmlString = new String(xmlData, java.nio.charset.StandardCharsets.UTF_8);
        if (containsSuspiciousPatterns(xmlString)) {
            logger.severe(String.format("[%s] Potential XXE attack detected and blocked", traceId));
            // Alert security team
            alertSecurityTeam(traceId, xmlString);
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body("Invalid XML content");
        }

        try {
            // Defense Layer 3: Secure parsing
            DocumentBuilder builder = SECURE_DOC_FACTORY.newDocumentBuilder();
            Document doc = builder.parse(new InputSource(new StringReader(xmlString)));

            logger.info(String.format("[%s] XML parsed successfully", traceId));

            // Process the document safely
            String result = processDocument(doc);
            return ResponseEntity.ok(result);

        } catch (org.xml.sax.SAXParseException e) {
            logger.warning(String.format("[%s] XML parse error (possible attack): %s", 
                    traceId, e.getMessage()));
            return ResponseEntity.badRequest().body("Invalid XML format");
        } catch (Exception e) {
            logger.severe(String.format("[%s] Unexpected error parsing XML: %s", 
                    traceId, e.getMessage()));
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body("Error processing XML");
        }
    }

    // Defense Layer 2: Pattern-based detection
    private boolean containsSuspiciousPatterns(String xml) {
        String lowerXml = xml.toLowerCase();
        return lowerXml.contains("<!entity") ||
               lowerXml.contains("<!doctype") ||
               lowerXml.contains("system ") ||
               lowerXml.contains("public ") ||
               lowerXml.contains("file://") ||
               lowerXml.contains("http://") ||
               lowerXml.contains("https://") ||
               lowerXml.contains("ftp://") ||
               lowerXml.contains("gopher://");
    }

    private void alertSecurityTeam(String traceId, String payload) {
        // Integration with SIEM/alerting system
        logger.severe(String.format("SECURITY_ALERT: XXE attempt detected [%s]", traceId));
        // Send to security monitoring system
    }

    private String processDocument(Document doc) {
        // Safe document processing
        return "Processed successfully";
    }
}
```

**Defense in Depth Layers**:

1. **Parser Configuration Layer** - Disable all dangerous features at factory level:
```java
// This is the PRIMARY defense - must be set correctly
factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
```

2. **Input Validation Layer** - Pre-parse detection of attack patterns:
```java
// Detect DOCTYPE and ENTITY declarations before parsing
if (xml.toLowerCase().contains("<!entity") || xml.toLowerCase().contains("<!doctype")) {
    throw new SecurityException("DOCTYPE declarations not allowed");
}
```

3. **Size Limiting Layer** - Prevent resource exhaustion attacks:
```java
// Billion Laughs attack uses exponential entity expansion
if (xmlData.length > MAX_XML_SIZE) {
    return ResponseEntity.status(HttpStatus.PAYLOAD_TOO_LARGE).build();
}
```

**Additional Protections**:

- **JAXB Security** (if using JAXB for unmarshalling):
```java
JAXBContext context = JAXBContext.newInstance(MyClass.class);
Unmarshaller unmarshaller = context.createUnmarshaller();
SAXParserFactory spf = SAXParserFactory.newInstance();
spf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
Source xmlSource = new SAXSource(spf.newSAXParser().getXMLReader(), 
                                  new InputSource(new StringReader(xml)));
MyClass obj = (MyClass) unmarshaller.unmarshal(xmlSource);
```

- **Spring Security Configuration** (application.properties):
```text
# Limit request body size globally
spring.servlet.multipart.max-file-size=1MB
spring.servlet.multipart.max-request-size=1MB
server.tomcat.max-http-form-post-size=1MB
```

- **Monitoring/Alerting**: Log all XML parsing failures to SIEM for security team review
- **WAF Rules**: Block requests containing DOCTYPE or ENTITY declarations at network edge
- **Consider Alternatives**: For simple data exchange, use JSON instead of XML to eliminate XXE risk entirely

When dealing with third-party XML libraries or high-security production environments, you need multiple defense layers since library defaults can change between versions and different parsers have different behaviors.

**PRODUCTION PATTERN**:

```go
package main

import (
	"bytes"
	"context"
	"encoding/xml"
	"errors"
	"fmt"
	"io"
	"log/slog"
	"net/http"
	"os"
	"regexp"
	"strings"
	"sync"
	"time"
)

// Configuration with secure defaults
type XMLParserConfig struct {
	MaxSize           int64
	MaxDepth          int
	MaxAttributes     int
	AllowDTD          bool
	AllowExternalRef  bool
	Timeout           time.Duration
	AllowedRootTags   []string
}

var defaultConfig = XMLParserConfig{
	MaxSize:          1024 * 1024,  // 1MB
	MaxDepth:         20,
	MaxAttributes:    50,
	AllowDTD:         false,        // CRITICAL: Disable DTD
	AllowExternalRef: false,        // CRITICAL: Disable external refs
	Timeout:          5 * time.Second,
	AllowedRootTags:  []string{"request", "data", "message"},
}

// Security-focused XML parser wrapper
type SecureXMLParser struct {
	config XMLParserConfig
	logger *slog.Logger
	metrics *XMLMetrics
}

type XMLMetrics struct {
	mu               sync.Mutex
	TotalRequests    int64
	RejectedDTD      int64
	RejectedSize     int64
	RejectedMalformed int64
	Successful       int64
}

type UserRequest struct {
	XMLName xml.Name `xml:"request"`
	Name    string   `xml:"name"`
	Email   string   `xml:"email"`
	Message string   `xml:"message"`
}

// Dangerous patterns to detect
var (
	dtdPattern = regexp.MustCompile(`(?i)<!DOCTYPE[^>]*>`)
	entityPattern = regexp.MustCompile(`(?i)<!ENTITY[^>]*>`)
	externalRefPattern = regexp.MustCompile(`(?i)(SYSTEM|PUBLIC)\s+["'][^"']*["']`)
	parameterEntityPattern = regexp.MustCompile(`%[a-zA-Z_][a-zA-Z0-9_]*;`)
)

func NewSecureXMLParser(config XMLParserConfig, logger *slog.Logger) *SecureXMLParser {
	return &SecureXMLParser{
		config:  config,
		logger:  logger,
		metrics: &XMLMetrics{},
	}
}

// Pre-parse security scan
func (p *SecureXMLParser) scanForThreats(content []byte) error {
	contentStr := string(content)

	// Check for DTD declarations
	if !p.config.AllowDTD && dtdPattern.MatchString(contentStr) {
		return errors.New("DTD declarations are not allowed")
	}

	// Check for entity declarations
	if entityPattern.MatchString(contentStr) {
		return errors.New("ENTITY declarations are not allowed")
	}

	// Check for external references
	if !p.config.AllowExternalRef && externalRefPattern.MatchString(contentStr) {
		return errors.New("external references are not allowed")
	}

	// Check for parameter entities
	if parameterEntityPattern.MatchString(contentStr) {
		return errors.New("parameter entities are not allowed")
	}

	// Check for XML bomb patterns (Billion Laughs)
	if strings.Count(contentStr, "&") > 100 {
		return errors.New("excessive entity references detected")
	}

	return nil
}

// Depth-limiting decoder wrapper
type depthLimitingDecoder struct {
	*xml.Decoder
	currentDepth int
	maxDepth     int
}

func (d *depthLimitingDecoder) Token() (xml.Token, error) {
	tok, err := d.Decoder.Token()
	if err != nil {
		return tok, err
	}

	switch tok.(type) {
	case xml.StartElement:
		d.currentDepth++
		if d.currentDepth > d.maxDepth {
			return nil, errors.New("maximum XML depth exceeded")
		}
	case xml.EndElement:
		d.currentDepth--
	}

	return tok, nil
}

// Main parsing function with full security controls
func (p *SecureXMLParser) ParseSecure(ctx context.Context, r io.Reader, v interface{}) error {
	p.metrics.mu.Lock()
	p.metrics.TotalRequests++
	p.metrics.mu.Unlock()

	// Apply timeout
	ctx, cancel := context.WithTimeout(ctx, p.config.Timeout)
	defer cancel()

	// Read with size limit
	limitedReader := io.LimitReader(r, p.config.MaxSize+1)
	content, err := io.ReadAll(limitedReader)
	if err != nil {
		return fmt.Errorf("failed to read XML: %w", err)
	}

	if int64(len(content)) > p.config.MaxSize {
		p.metrics.mu.Lock()
		p.metrics.RejectedSize++
		p.metrics.mu.Unlock()
		p.logger.Warn("XML size limit exceeded", "size", len(content))
		return errors.New("XML content exceeds maximum size")
	}

	// Pre-parse security scan
	if err := p.scanForThreats(content); err != nil {
		p.metrics.mu.Lock()
		p.metrics.RejectedDTD++
		p.metrics.mu.Unlock()
		p.logger.Warn("XML security threat detected", "error", err)
		return fmt.Errorf("security violation: %w", err)
	}

	// Parse with depth limiting
	baseDecoder := xml.NewDecoder(bytes.NewReader(content))
	baseDecoder.Strict = true

	// Custom entity resolver that blocks all entities
	baseDecoder.Entity = map[string]string{}

	decoder := &depthLimitingDecoder{
		Decoder:  baseDecoder,
		maxDepth: p.config.MaxDepth,
	}

	// Parse in goroutine with context cancellation
	done := make(chan error, 1)
	go func() {
		done <- decoder.Decode(v)
	}()

	select {
	case <-ctx.Done():
		return errors.New("XML parsing timeout")
	case err := <-done:
		if err != nil {
			p.metrics.mu.Lock()
			p.metrics.RejectedMalformed++
			p.metrics.mu.Unlock()
			return fmt.Errorf("XML parsing failed: %w", err)
		}
	}

	p.metrics.mu.Lock()
	p.metrics.Successful++
	p.metrics.mu.Unlock()

	return nil
}

// HTTP handler with full production controls
func createXMLHandler(parser *SecureXMLParser) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		// Validate Content-Type
		contentType := r.Header.Get("Content-Type")
		if !strings.Contains(contentType, "application/xml") &&
			!strings.Contains(contentType, "text/xml") {
			http.Error(w, "Content-Type must be application/xml", http.StatusUnsupportedMediaType)
			return
		}

		// Create request context with tracing
		ctx := r.Context()
		requestID := r.Header.Get("X-Request-ID")
		if requestID == "" {
			requestID = generateRequestID()
		}

		logger := parser.logger.With("request_id", requestID, "remote_addr", r.RemoteAddr)

		var req UserRequest
		if err := parser.ParseSecure(ctx, r.Body, &req); err != nil {
			logger.Error("XML parsing failed", "error", err)

			// Don't leak internal error details
			if strings.Contains(err.Error(), "security violation") {
				http.Error(w, "Invalid XML content", http.StatusBadRequest)
			} else if strings.Contains(err.Error(), "timeout") {
				http.Error(w, "Request timeout", http.StatusRequestTimeout)
			} else {
				http.Error(w, "Failed to process XML", http.StatusBadRequest)
			}
			return
		}

		// Validate parsed content
		if err := validateUserRequest(&req); err != nil {
			logger.Warn("Request validation failed", "error", err)
			http.Error(w, "Invalid request data", http.StatusBadRequest)
			return
		}

		logger.Info("XML request processed successfully", "name", req.Name)

		// Set security headers
		w.Header().Set("Content-Type", "application/json")
		w.Header().Set("X-Content-Type-Options", "nosniff")
		w.Header().Set("X-Request-ID", requestID)

		fmt.Fprintf(w, `{"status":"success","name":"%s"}`, req.Name)
	}
}

func validateUserRequest(req *UserRequest) error {
	if len(req.Name) == 0 || len(req.Name) > 100 {
		return errors.New("invalid name length")
	}
	if len(req.Email) == 0 || len(req.Email) > 255 {
		return errors.New("invalid email length")
	}
	// Additional validation...
	return nil
}

func generateRequestID() string {
	return fmt.Sprintf("%d", time.Now().UnixNano())
}

func main() {
	// Production logger
	logger := slog.New(slog.NewJSONHandler(os.Stdout, &slog.HandlerOptions{
		Level: slog.LevelInfo,
	}))

	// Create secure parser
	parser := NewSecureXMLParser(defaultConfig, logger)

	// Metrics endpoint
	http.HandleFunc("/metrics", func(w http.ResponseWriter, r *http.Request) {
		parser.metrics.mu.Lock()
		defer parser.metrics.mu.Unlock()
		fmt.Fprintf(w, "xml_requests_total %d\n", parser.metrics.TotalRequests)
		fmt.Fprintf(w, "xml_rejected_dtd %d\n", parser.metrics.RejectedDTD)
		fmt.Fprintf(w, "xml_rejected_size %d\n", parser.metrics.RejectedSize)
		fmt.Fprintf(w, "xml_successful %d\n", parser.metrics.Successful)
	})

	http.HandleFunc("/api/xml", createXMLHandler(parser))

	logger.Info("Starting secure XML server", "port", 8080)
	http.ListenAndServe(":8080", nil)
}
