        // VULNERABLE: No XXE protection configured
        $xml = simplexml_load_string($xmlData);

        if ($xml === false) {
            return ['error' => 'Invalid XML'];
        }

        // Process the XML data
        $result = [];
        foreach ($xml->item as $item) {
            $result[] = [
                'name' => (string)$item->name,
                'value' => (string)$item->value
            ];
        }

        return $result;
    }

    // VULNERABLE: DOMDocument without protection
    public function loadXMLDocument($xmlData) {
        $doc = new DOMDocument();
        // DANGEROUS: External entities enabled by default in older PHP
        $doc->loadXML($xmlData);
        return $doc;
    }
}

// Usage
