```java
// SecureXMLService.java - Production service with monitoring
package com.example.xmlprocessor.service;

import io.micrometer.core.instrument.Counter;
import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Timer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.w3c.dom.Document;
import org.xml.sax.SAXException;

import javax.xml.XMLConstants;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.ParserConfigurationException;
import java.io.IOException;
import java.io.InputStream;
import java.util.concurrent.TimeUnit;

@Service
public class SecureXMLService {
    private static final Logger logger = LoggerFactory.getLogger(SecureXMLService.class);
    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    private final DocumentBuilderFactory secureFactory;
    private final Counter xmlParseSuccessCounter;
    private final Counter xmlParseFailureCounter;
    private final Counter xxeAttemptCounter;
    private final Timer xmlParseTimer;

    public SecureXMLService(MeterRegistry registry) {
        this.secureFactory = createSecureFactory();
        this.xmlParseSuccessCounter = registry.counter("xml.parse.success");
        this.xmlParseFailureCounter = registry.counter("xml.parse.failure");
        this.xxeAttemptCounter = registry.counter("xml.xxe.attempt.blocked");
        this.xmlParseTimer = registry.timer("xml.parse.duration");
    }

    private DocumentBuilderFactory createSecureFactory() {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        try {
            // PRIMARY DEFENSE: Disable DOCTYPE declarations entirely
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);

            // DEFENSE IN DEPTH: Disable external entities even if DOCTYPE sneaks through
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

            // Prevent XInclude attacks
            factory.setXIncludeAware(false);
            factory.setExpandEntityReferences(false);

            // Block external access completely
            factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

            // Enable secure processing mode
            factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);

            logger.info("Secure DocumentBuilderFactory initialized with XXE protections");
            return factory;

        } catch (ParserConfigurationException e) {
            logger.error("CRITICAL: Failed to configure secure XML parser", e);
            throw new SecurityException("XML security initialization failed", e);
        }
    }

    public Document parseXMLSecurely(InputStream xmlInput, String requestId, String clientIp) 
            throws XMLSecurityException {
        long startTime = System.nanoTime();

        try {
            DocumentBuilder builder = secureFactory.newDocumentBuilder();

            // Custom error handler to detect XXE attempts
            builder.setErrorHandler(new XXEDetectionErrorHandler(requestId, clientIp, xxeAttemptCounter));

            Document doc = builder.parse(xmlInput);

            xmlParseSuccessCounter.increment();
            xmlParseTimer.record(System.nanoTime() - startTime, TimeUnit.NANOSECONDS);

            logger.debug("XML parsed successfully for request {}", requestId);
            return doc;

        } catch (SAXException e) {
            xmlParseFailureCounter.increment();

            // Check for XXE attack indicators
            if (isXXEAttempt(e)) {
                xxeAttemptCounter.increment();
                securityLogger.warn("SECURITY_ALERT: Potential XXE attack blocked. " +
                    "RequestId={}, ClientIP={}, Error={}", requestId, clientIp, e.getMessage());
                throw new XMLSecurityException("XML processing rejected for security reasons", e);
            }

            logger.warn("XML parsing failed for request {}: {}", requestId, e.getMessage());
            throw new XMLSecurityException("Invalid XML document", e);

        } catch (IOException e) {
            xmlParseFailureCounter.increment();
            logger.error("IO error during XML parsing for request {}", requestId, e);
            throw new XMLSecurityException("Failed to read XML input", e);

        } catch (ParserConfigurationException e) {
            xmlParseFailureCounter.increment();
            logger.error("Parser configuration error", e);
            throw new XMLSecurityException("XML parser configuration error", e);
        }
    }

    private boolean isXXEAttempt(SAXException e) {
        String message = e.getMessage().toLowerCase();
        return message.contains("doctype") ||
               message.contains("entity") ||
               message.contains("external") ||
               message.contains("system") ||
               message.contains("public");
    }
}
