**Key Security Controls**:
- **noent: false** - Prevents entity substitution, blocking XXE payload execution
- **dtdload: false** - Prevents loading external DTDs that could define malicious entities
- **nonet: true** - Blocks network access, preventing SSRF via external entity URLs
- **DOCTYPE blocking** - Rejects any XML with DOCTYPE declarations as defense in depth

For production environments, I recommend using `fast-xml-parser` which is XXE-safe by default and doesn't process DTDs. Here's a comprehensive production pattern with multiple data sources:

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const { XMLParser, XMLValidator } = require('fast-xml-parser');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const crypto = require('crypto');

const app = express();

// Security headers
app.use(helmet());

// Rate limiting for XML endpoints
const xmlLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: { error: 'Too many requests, please try again later' },
  standardHeaders: true,
  legacyHeaders: false
});

// Request size limit
app.use(express.text({ type: 'application/xml', limit: '50kb' }));

// SECURE XML parser configuration (fast-xml-parser is XXE-safe by default)
const XML_PARSER_OPTIONS = {
  ignoreAttributes: false,
  attributeNamePrefix: '@_',
  allowBooleanAttributes: true,
  parseTagValue: true,
  parseAttributeValue: true,
  trimValues: true,
  // Strict mode for better security
  isArray: (name, jpath, isLeafNode, isAttribute) => {
    // Define which elements should always be arrays
    return ['item', 'product', 'lineItem'].includes(name);
  }
};

// XML Schema definition for validation
const ORDER_SCHEMA = {
  requiredFields: ['orderId', 'customer', 'amount'],
  maxFieldLengths: {
    orderId: 50,
    customer: 200,
    amount: 20
  },
  patterns: {
    orderId: /^[A-Z0-9\-]{1,50}$/,
    amount: /^\d+(\.\d{1,2})?$/
  }
};

class SecureXMLProcessor {
  constructor(options = {}) {
    this.parser = new XMLParser(XML_PARSER_OPTIONS);
    this.logger = options.logger || console;
    this.metrics = options.metrics || { increment: () => {} };
  }

  // DEFENSE 1: Pre-parse security checks
  preParseValidation(xmlString, requestId) {
    const threats = [];

    // Check for DOCTYPE (XXE vector)
    if (/<!DOCTYPE/i.test(xmlString)) {
      threats.push('DOCTYPE_DETECTED');
    }

    // Check for ENTITY declarations
    if (/<!ENTITY/i.test(xmlString)) {
      threats.push('ENTITY_DETECTED');
    }

    // Check for external references
    if (/SYSTEM\s+["'][^"']+["']/i.test(xmlString)) {
      threats.push('EXTERNAL_REFERENCE_DETECTED');
    }

    // Check for PUBLIC identifier
    if (/PUBLIC\s+["'][^"']+["']/i.test(xmlString)) {
      threats.push('PUBLIC_IDENTIFIER_DETECTED');
    }

    // Check for parameter entities
    if (/%[a-zA-Z0-9]+;/.test(xmlString)) {
      threats.push('PARAMETER_ENTITY_DETECTED');
    }

    // Check for suspicious protocols
    if (/(?:file|http|https|ftp|gopher|expect|php):\/\//i.test(xmlString)) {
      threats.push('SUSPICIOUS_PROTOCOL_DETECTED');
    }

    if (threats.length > 0) {
      this.logger.warn({
        event: 'xxe_threat_blocked',
        requestId,
        threats,
        timestamp: new Date().toISOString()
      });
      this.metrics.increment('xml.xxe_blocked', { threats: threats.join(',') });
      return { valid: false, threats };
    }

    return { valid: true };
  }

  // DEFENSE 2: XML structure validation
  validateXMLStructure(xmlString) {
    const result = XMLValidator.validate(xmlString, {
      allowBooleanAttributes: true
    });

    if (result !== true) {
      return { valid: false, error: result.err.msg };
    }
    return { valid: true };
  }

  // DEFENSE 3: Schema validation
  validateSchema(parsedData, schema, requestId) {
    const errors = [];
    const root = parsedData.order || parsedData;

    // Check required fields
    for (const field of schema.requiredFields) {
      if (!root[field]) {
        errors.push(`Missing required field: ${field}`);
      }
    }

    // Check field lengths
    for (const [field, maxLength] of Object.entries(schema.maxFieldLengths)) {
      if (root[field] && String(root[field]).length > maxLength) {
        errors.push(`Field ${field} exceeds maximum length of ${maxLength}`);
      }
    }

    // Check patterns
    for (const [field, pattern] of Object.entries(schema.patterns)) {
      if (root[field] && !pattern.test(String(root[field]))) {
        errors.push(`Field ${field} has invalid format`);
      }
    }

    if (errors.length > 0) {
      this.logger.warn({
        event: 'xml_schema_validation_failed',
        requestId,
        errors,
        timestamp: new Date().toISOString()
      });
      return { valid: false, errors };
    }

    return { valid: true };
  }

  // Main processing method
  async processXML(xmlString, schema, requestId) {
    // Step 1: Pre-parse security validation
    const preCheck = this.preParseValidation(xmlString, requestId);
    if (!preCheck.valid) {
      throw new XMLSecurityError('Potential XXE attack detected', preCheck.threats);
    }

    // Step 2: Structural validation
    const structureCheck = this.validateXMLStructure(xmlString);
    if (!structureCheck.valid) {
      throw new XMLValidationError('Invalid XML structure', structureCheck.error);
    }

    // Step 3: Parse XML (fast-xml-parser doesn't process DTDs)
    const parsedData = this.parser.parse(xmlString);

    // Step 4: Schema validation
    const schemaCheck = this.validateSchema(parsedData, schema, requestId);
    if (!schemaCheck.valid) {
      throw new XMLValidationError('Schema validation failed', schemaCheck.errors);
    }

    // Step 5: Sanitize output
    return this.sanitizeOutput(parsedData.order || parsedData);
  }

  sanitizeOutput(data) {
    const sanitized = {};
    for (const [key, value] of Object.entries(data)) {
      if (typeof value === 'string') {
        // Remove potential entity references and control characters
        sanitized[key] = value
          .replace(/&[a-zA-Z0-9#]+;/g, '')
          .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '')
          .substring(0, 10000);
      } else if (typeof value === 'number') {
        sanitized[key] = value;
      } else if (typeof value === 'object' && value !== null) {
        sanitized[key] = this.sanitizeOutput(value);
      }
    }
    return sanitized;
  }
}

// Custom error classes
class XMLSecurityError extends Error {
  constructor(message, threats) {
    super(message);
    this.name = 'XMLSecurityError';
    this.threats = threats;
    this.statusCode = 400;
  }
}

class XMLValidationError extends Error {
  constructor(message, details) {
    super(message);
    this.name = 'XMLValidationError';
    this.details = details;
    this.statusCode = 400;
  }
}

// Initialize processor
const xmlProcessor = new SecureXMLProcessor({
  logger: console,
  metrics: { increment: () => {} }
});

// API endpoint
app.post('/api/orders/xml', xmlLimiter, async (req, res) => {
  const requestId = crypto.randomUUID();
  const startTime = Date.now();

  console.log({
    event: 'xml_request_received',
    requestId,
    ip: req.ip,
    contentLength: req.get('content-length'),
    timestamp: new Date().toISOString()
  });

  try {
    const xmlData = req.body;

    if (!xmlData || typeof xmlData !== 'string') {
      return res.status(400).json({ 
        error: 'XML body required',
        requestId 
      });
    }

    const result = await xmlProcessor.processXML(xmlData, ORDER_SCHEMA, requestId);

    console.log({
      event: 'xml_processed_successfully',
      requestId,
      duration: Date.now() - startTime,
      timestamp: new Date().toISOString()
    });

    res.json({ 
      success: true, 
      order: result,
      requestId 
    });

  } catch (error) {
    console.error({
      event: 'xml_processing_error',
      requestId,
      errorType: error.name,
      errorMessage: error.message,
      duration: Date.now() - startTime,
      timestamp: new Date().toISOString()
    });

    const statusCode = error.statusCode || 500;
    const message = statusCode === 500 ? 'Internal server error' : error.message;

    res.status(statusCode).json({ 
      error: message,
      requestId 
    });
  }
});

// Health check endpoint
app.get('/health', (req, res) => {
  res.json({ status: 'healthy', timestamp: new Date().toISOString() });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Secure XML API running on port ${PORT}`);
});
```

**Defense in Depth Layers**:

1. **Library Selection** - `fast-xml-parser` doesn't process DTDs or external entities by design, eliminating XXE at the parser level

2. **Pre-Parse Pattern Detection** - Regex-based detection of DOCTYPE, ENTITY, SYSTEM, and suspicious protocols before parsing even begins

3. **Schema Validation** - Strict validation of expected fields, lengths, and formats prevents unexpected data injection

4. **Output Sanitization** - Post-processing removes any residual entity references or control characters

**Additional Protections**:
- **Request size limiting** - 50kb limit prevents billion laughs DoS attacks
- **Rate limiting** - 100 requests per 15 minutes prevents abuse
- **Security headers via Helmet** - Adds CSP, X-Frame-Options, etc.
- **Structured logging** - All requests logged with unique request IDs for forensic analysis
- **Error handling** - Never expose internal error details to clients
- **Metrics collection** - Track blocked XXE attempts for security monitoring

