Using Java's DocumentBuilder with default settings is **extremely dangerous** and has led to critical vulnerabilities in enterprise software. The 2024 Ivanti Connect Secure breach (CVE-2024-21893) exploited XXE to compromise 1,700+ organizations.

**VULNERABLE CODE**:

```java
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import org.w3c.dom.Document;
import org.w3c.dom.NodeList;
import java.io.InputStream;

public class XmlConfigParser {

    public Document parseUserConfig(InputStream xmlInput) throws Exception {
        // VULNERABLE: Default DocumentBuilder allows XXE attacks
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        DocumentBuilder builder = factory.newDocumentBuilder();

        // Attacker-controlled XML is parsed without protection
        Document doc = builder.parse(xmlInput);

        return doc;
    }

    public String getUserSetting(InputStream xmlInput, String settingName) throws Exception {
        Document doc = parseUserConfig(xmlInput);
        NodeList nodes = doc.getElementsByTagName(settingName);

        if (nodes.getLength() > 0) {
            return nodes.item(0).getTextContent();
        }
        return null;
    }
}
```

**Attack Payload**:
```xml
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE config [
  <!ENTITY xxe SYSTEM "file:///etc/passwd">
]>
<config>
  <username>&xxe;</username>
  <theme>dark</theme>
</config>
```

**Advanced Attack - AWS Credential Theft**:
```xml
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE config [
  <!ENTITY xxe SYSTEM "http://169.254.169.254/latest/meta-data/iam/security-credentials/">
]>
<config>
  <data>&xxe;</data>
</config>
```

**Why This Is Dangerous**:
- External entities allow reading arbitrary local files (/etc/passwd, application.properties)
- SSRF attacks can access internal services and cloud metadata endpoints
- Billion laughs attack causes denial of service through exponential entity expansion
- Parameter entities can exfiltrate data to attacker-controlled servers

**SECURE VERSION**:

```java
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.XMLConstants;
import org.w3c.dom.Document;
import org.w3c.dom.NodeList;
import java.io.InputStream;
import java.util.logging.Logger;

public class SecureXmlConfigParser {
    private static final Logger logger = Logger.getLogger(SecureXmlConfigParser.class.getName());

    private DocumentBuilderFactory createSecureFactory() throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();

        // CRITICAL: Disable all external entity processing
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

        // Additional hardening
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);
        factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
        factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

        return factory;
    }

    public Document parseUserConfig(InputStream xmlInput) throws Exception {
        DocumentBuilderFactory factory = createSecureFactory();
        DocumentBuilder builder = factory.newDocumentBuilder();

        logger.info("Parsing XML with XXE protection enabled");
        Document doc = builder.parse(xmlInput);

        return doc;
    }

    public String getUserSetting(InputStream xmlInput, String settingName) throws Exception {
        Document doc = parseUserConfig(xmlInput);
        NodeList nodes = doc.getElementsByTagName(settingName);

        if (nodes.getLength() > 0) {
            return nodes.item(0).getTextContent();
        }
        return null;
    }
}
```

**Key Security Controls**:
- `disallow-doctype-decl` completely blocks DOCTYPE declarations, preventing all XXE attacks
- `external-general-entities` and `external-parameter-entities` disable entity resolution
- `ACCESS_EXTERNAL_DTD` and `ACCESS_EXTERNAL_SCHEMA` prevent network access during parsing
- `setExpandEntityReferences(false)` adds defense in depth against entity expansion attacks

Different XML parsing APIs require different security configurations. Here's a production-ready approach that covers SAX, StAX, JAXB, and third-party libraries with defense in depth.

**PRODUCTION PATTERN**:

```java
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.SAXParserFactory;
import javax.xml.stream.XMLInputFactory;
import javax.xml.transform.TransformerFactory;
import javax.xml.validation.SchemaFactory;
import javax.xml.XMLConstants;
import javax.xml.bind.JAXBContext;
import javax.xml.bind.Unmarshaller;
import org.xml.sax.InputSource;
import org.xml.sax.XMLReader;
import java.io.InputStream;
import java.io.StringReader;
import java.util.logging.Logger;
import java.util.concurrent.ConcurrentHashMap;

public class SecureXmlParserFactory {
    private static final Logger logger = Logger.getLogger(SecureXmlParserFactory.class.getName());
    private static final int MAX_XML_SIZE_BYTES = 10 * 1024 * 1024; // 10MB limit
    private static final ConcurrentHashMap<String, Integer> parseAttempts = new ConcurrentHashMap<>();

    /**
     * Creates a secure DocumentBuilderFactory with all XXE protections
     */
    public static DocumentBuilderFactory createSecureDocumentBuilderFactory() {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();

            // Primary defense: Disable DOCTYPE completely
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);

            // Defense in depth: Disable external entities
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

            // Prevent XInclude attacks
            factory.setXIncludeAware(false);
            factory.setExpandEntityReferences(false);

            // Block external access
            factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

            logger.fine("Created secure DocumentBuilderFactory");
            return factory;

        } catch (Exception e) {
            logger.severe("Failed to configure secure XML parser: " + e.getMessage());
            throw new SecurityException("XML parser configuration failed", e);
        }
    }

    /**
     * Creates a secure SAXParserFactory
     */
    public static SAXParserFactory createSecureSAXParserFactory() {
        try {
            SAXParserFactory factory = SAXParserFactory.newInstance();

            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            factory.setXIncludeAware(false);

            logger.fine("Created secure SAXParserFactory");
            return factory;

        } catch (Exception e) {
            logger.severe("Failed to configure secure SAX parser: " + e.getMessage());
            throw new SecurityException("SAX parser configuration failed", e);
        }
    }

    /**
     * Creates a secure StAX XMLInputFactory
     */
    public static XMLInputFactory createSecureXMLInputFactory() {
        XMLInputFactory factory = XMLInputFactory.newInstance();

        // Disable DTD processing entirely
        factory.setProperty(XMLInputFactory.SUPPORT_DTD, false);
        factory.setProperty(XMLInputFactory.IS_SUPPORTING_EXTERNAL_ENTITIES, false);

        // Additional StAX-specific protections
        factory.setProperty(XMLInputFactory.IS_REPLACING_ENTITY_REFERENCES, false);

        logger.fine("Created secure XMLInputFactory");
        return factory;
    }

    /**
     * Creates a secure TransformerFactory for XSLT
     */
    public static TransformerFactory createSecureTransformerFactory() {
        try {
            TransformerFactory factory = TransformerFactory.newInstance();

            factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_STYLESHEET, "");
            factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);

            logger.fine("Created secure TransformerFactory");
            return factory;

        } catch (Exception e) {
            logger.severe("Failed to configure secure transformer: " + e.getMessage());
            throw new SecurityException("Transformer configuration failed", e);
        }
    }

    /**
     * Creates a secure JAXB Unmarshaller
     */
    public static <T> Unmarshaller createSecureUnmarshaller(Class<T> clazz) {
        try {
            JAXBContext context = JAXBContext.newInstance(clazz);
            Unmarshaller unmarshaller = context.createUnmarshaller();

            // Use secure XMLInputFactory as source
            XMLInputFactory xif = createSecureXMLInputFactory();

            logger.fine("Created secure JAXB Unmarshaller for " + clazz.getName());
            return unmarshaller;

        } catch (Exception e) {
            logger.severe("Failed to configure secure JAXB: " + e.getMessage());
            throw new SecurityException("JAXB configuration failed", e);
        }
    }

    /**
     * Validates XML input before parsing with rate limiting and size checks
     */
    public static void validateXmlInput(InputStream xmlInput, String clientId) 
            throws SecurityException {

        // Rate limiting: Max 100 parse attempts per minute per client
        Integer attempts = parseAttempts.compute(clientId, (k, v) -> v == null ? 1 : v + 1);
        if (attempts > 100) {
            logger.warning("Rate limit exceeded for client: " + clientId);
            throw new SecurityException("XML parsing rate limit exceeded");
        }

        // Size validation happens during stream processing
        logger.info("XML validation passed for client: " + clientId);
    }

    /**
     * Production-ready XML parsing with full security controls
     */
    public static org.w3c.dom.Document parseXmlSecurely(
            InputStream xmlInput, 
            String clientId,
            String requestId) throws Exception {

        long startTime = System.currentTimeMillis();

        try {
            // Pre-parse validation
            validateXmlInput(xmlInput, clientId);

            // Create secure parser
            DocumentBuilderFactory factory = createSecureDocumentBuilderFactory();
            javax.xml.parsers.DocumentBuilder builder = factory.newDocumentBuilder();

            // Parse with secure settings
            org.w3c.dom.Document doc = builder.parse(xmlInput);

            // Audit logging
            long duration = System.currentTimeMillis() - startTime;
            logger.info(String.format(
                "XML parsed successfully - requestId=%s, clientId=%s, duration=%dms",
                requestId, clientId, duration
            ));

            return doc;

        } catch (org.xml.sax.SAXParseException e) {
            // Log potential attack attempt
            logger.warning(String.format(
                "XML parse error (possible attack) - requestId=%s, clientId=%s, error=%s",
                requestId, clientId, e.getMessage()
            ));
            throw new SecurityException("Invalid XML document");

        } catch (Exception e) {
            logger.severe(String.format(
                "XML parsing failed - requestId=%s, clientId=%s, error=%s",
                requestId, clientId, e.getMessage()
            ));
            throw e;
        }
    }

    // Scheduled task to reset rate limits (call every minute)
    public static void resetRateLimits() {
        parseAttempts.clear();
        logger.fine("Rate limits reset");
    }
}
